public class Program3_Reverse {

	/**
	 * @param args
	 */
	public static void main(String[] args) {
		// TODO Auto-generated method stub
    int num=10;
    while(num >= 0 ) {
    	System.out.print( num);
    	num--;
    	
    }
    System.out.print( num);
	}

}
